# BAD: agent recreated every call — loses session history
def handle(msg):
    agent = Agent(model=OpenAIChat(id="gpt-4o"))
    return agent.run(msg)

# GOOD: single agent instance with storage
agent = Agent(
    model=OpenAIChat(id="gpt-4o"),
    storage=SqliteStorage(table_name="session", db_file="agent.db"),
    add_history_to_messages=True,
)

def handle(msg):
    return agent.run(msg)
